qss:
QWidget { background: #2a2118; color: #f4e7d0; font-family: Segoe UI, Arial, sans-serif; font-size: 10pt; }
QMainWindow, QDialog { background: #2a2118; }
QGroupBox { background: #35291d; border: 1px solid #735638; border-radius: 8px; margin-top: 12px; padding: 10px; font-weight: bold; }
QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 4px; color: #c58b3b; }
QTabWidget::pane { border: 1px solid #735638; background: #35291d; }
QTabBar::tab { background: #211811; color: #f4e7d0; padding: 8px 14px; border: 1px solid #735638; border-bottom: none; min-width: 100px; }
QTabBar::tab:selected { background: #8a5a22; color: #fff4df; font-weight: bold; }
QTabBar::tab:hover { background: #5a3d21; color: #fff4df; }
QPushButton { background: #5a3d21; color: #fff4df; border: 1px solid #c58b3b; border-radius: 6px; padding: 7px 12px; font-weight: 600; }
QPushButton:hover { background: #c58b3b; color: #fff4df; }
QPushButton:disabled { background: #76634c; color: #211811; border-color: #735638; }
QLineEdit, QTextEdit, QTextBrowser, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox { background: #211811; color: #f4e7d0; border: 1px solid #735638; border-radius: 5px; padding: 5px; selection-background-color: #c58b3b; selection-color: #fff4df; }
QComboBox QAbstractItemView { background: #211811; color: #f4e7d0; selection-background-color: #c58b3b; selection-color: #fff4df; border: 1px solid #735638; }
QTableWidget { background: #211811; alternate-background-color: #35291d; color: #f4e7d0; gridline-color: #735638; selection-background-color: #c58b3b; selection-color: #fff4df; }
QHeaderView::section { background: #8a5a22; color: #fff4df; padding: 6px; border: 1px solid #735638; font-weight: bold; }
QScrollBar:vertical { background: #35291d; width: 14px; }
QScrollBar::handle:vertical { background: #c58b3b; border-radius: 6px; min-height: 24px; }
QScrollBar:horizontal { background: #35291d; height: 14px; }
QScrollBar::handle:horizontal { background: #c58b3b; border-radius: 6px; min-width: 24px; }
QCheckBox { spacing: 6px; }
QLabel { color: #f4e7d0; }
